#!/usr/bin/env bash
# sop-seo.sh — 端到端内容生产 SOP（核心 · 选题→标题封面→正文→制作→标签SEO→发布→复盘） SOP walkthrough for 小红书 AI 自媒体博主.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="小红书 AI 自媒体博主"
WORKFLOW="端到端内容生产 SOP（核心 · 选题→标题封面→正文→制作→标签SEO→发布→复盘）"

usage() {
  cat <<EOF
sop-seo.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./sop-seo.sh             # interactive
  ./sop-seo.sh --dry-run
  ./sop-seo.sh --json
  ./sop-seo.sh --explain
  ./sop-seo.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "端到端内容生产 SOP（核心 · 选题→标题封面→正文→制作→标签SEO→发布→复盘）" 工作流。

一句话: 从"今天发什么"到"发出一条合规、有网感、能进流量池的 AI 辅助笔记"的完整闭环——AI-creator 的主干流程。

入门 SOP 共 9 步, 失败模式自检 3 项。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**选题**：四法二选一——① 数据平台(新红/千瓜/蝉小红)挖爆款话题/蓝海词 ② 让 AI 反查搜索下拉词出长尾选题 ③ 盯 3-5 个对标号高赞笔记 ④ 蹭热点×专业领域。AI 赛道易起号方向：AI工具测评/AI副业/AI教程/AI生活应用/AI+垂类 (evidence: [T03-S001, T02-S011, T04-S008])"
  "**标题**：6 公式选 1——数字型/痛点型/对比型/悬念型/干货型/情感型；核心 SEO 词前置。例「5个工具让效率翻倍」「为什么你的笔记没人看」(evidence: [T03-S001, T04-S012(B4), T02-S021])"
  "**封面**：三原则——大字+强对比色(标题占画面≥1/3)/3米外能看清/3-5 套固定差异化模板轮换；用 3:4 竖图(列表页展示面积最大)。工具即梦/可图直出主图 + 稿定/Canva 压大字报 (evidence: [T03-S001, T03-S005, T04-S012(B4), T02-S006])"
  "**正文**：6 段式——钩子(1-2句)→自我介绍(1句)→痛点共鸣(3-5句)→解决方案(5-8句)→真实案例(2-3句)→互动引导(1句)，全文 400-600 字，分点+口语化+利他+CTA (evidence: [T03-S001, T04-S009, T01-S001])"
  "**AI 出稿→人工重写**（详见 W4）：70% AI 初稿 + 30% 人工注入真实体验/细节，删 AI 腔。**这是合规护城河的核心一步**。(evidence: [T03-S001, T03-S002, T02-S020])"
  "**制作配图**：图文用即梦/Canva 出图；视频走 W3c；首图放钩子，第2-3张放干货提炼，中间放过程截图，末图放互动引导 (evidence: [T03-S001, T02-S005])"
  "**标签+SEO**：10 标签 = 3 大词(流量)+4 中词(精准)+3 长尾词(搜索)；核心词进标题+首段+图片标签 (evidence: [T03-S001, T04-S008(A5)])"
  "**发布**：黄金时段(晚 8-10 点/工作日午间/早通勤)；数据起势可投薯条加热 (evidence: [T03-S001, T04-S001(A3)])"
  "**复盘**（详见 W6）：发后 30 分钟内回前 10 条评论；每周日拉数据+拆爆款共性。(evidence: [T03-S001, T03-S005])"
)
declare -a FAILURE_MODES=(
  "纯 AI 直发不重写 → AI 味检测命中限流 + 撞稿。避免：强制 W4 人工重写。(evidence: [T03-S001, T02-S020])"
  "封面套同一模板 → 同质化稀释，CTR 持续走低。避免：3-5 套差异化模板轮换。(evidence: [T03-S001])"
  "选题红海无搜索量 → 0 曝光。避免：先用蝉小红查蓝海词(近7天笔记少)。(evidence: [T02-S014])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "sop-seo-walkthrough"
fi
